import * as React from "react";
import styles from "./WhyBlock.module.css";
import { IndicatorBar } from "../IndicatorBar/IndicatorBar";
import type { WhyPayload } from "../../scoring/match";
import { formatWhy } from "../../scoring/whyDisplay";

export interface WhyBlockProps {
  why: WhyPayload;
  /** Couleur du filet vertical à gauche (couleur saturée du thème). */
  accentVar: string;
  /** Numéro/libellé de la semaine de référence (ex: "S17"). */
  weekLabel: string;
}

/**
 * Encart "Pourquoi cette reco" affiché en page détail.
 * Filet vertical 4px coloré du thème + bandeau ivoire + mini-graph encadré.
 */
export const WhyBlock: React.FC<WhyBlockProps> = ({
  why,
  accentVar,
  weekLabel,
}) => {
  const detailText =
    `Vos ${why.label.toLowerCase()} ${
      why.inverse ? "passent sous le plancher" : "dépassent le seuil"
    } cible de ${why.threshold}${why.kind === "volume" ? "h" : "%"}. ` +
    `Cette recommandation adresse directement cet indicateur.`;

  return (
    <div
      className={styles.root}
      style={{ ["--why-accent" as string]: accentVar }}
    >
      <div className={styles.eyebrow}>Pourquoi cette reco</div>
      <div className={styles.title}>Détecté dans votre semaine {weekLabel}</div>
      <div className={styles.body}>{detailText}</div>
      <div className={styles.bar}>
        {(() => {
          const fmt = formatWhy(why);
          return (
            <IndicatorBar
              value={why.value}
              max={why.max}
              threshold={why.threshold}
              inverse={why.inverse}
              unit={fmt.unit}
              label={`semaine ${weekLabel}`}
              valueDisplay={fmt.valueDisplay}
              thresholdDisplay={fmt.thresholdDisplay}
            />
          );
        })()}
      </div>
    </div>
  );
};
