/**
 * Génération du rendu HTML des events de score Gr33t Recovery (v1.1 IRA).
 *
 * Structure "liste par facteur" (même UX que le TaskPane legacy SPEC.md v1,
 * adaptée aux 4 facteurs IRA v1.1) :
 *   - Header : IRA + libellé qualitatif
 *   - Par facteur : nom + résumé coloré + rows (meetings, mails, plages)
 *   - Footer : rappel politique QVCT
 *
 * Contraintes Outlook :
 *   - Styles inline uniquement (pas de <style>, pas de CSS externe)
 *   - Tables pour layout (compat Outlook Desktop Win32)
 *   - Polices système (DM Sans en fallback)
 */
import type { DailyScores, DailyMeeting, DailySend } from "../dashboard/rythme/scoring/daily";
import {
  DEFAULT_POLICY,
  workStartMin,
  workEndMin,
  transBeforeMs,
  transAfterMs,
  type QvctPolicy,
} from "../dashboard/rythme/config/policy";

export type { DailyScores };

// ─── Tokens couleurs ──────────────────────────────────────────────────────────
const COLOR_POSITIVE = "#4dad33";
const COLOR_INTERMEDIATE = "#ed6d2d";
const COLOR_NEGATIVE = "#ef4e78";
const COLOR_NEUTRAL = "#3e8f98";
const COLOR_PRIMARY = "#2266dd";
const COLOR_ON_SURFACE = "#1a1c1e";
const COLOR_ON_SURFACE_MUTED = "rgba(26, 28, 30, 0.6)";
const COLOR_SURFACE_VARIANT = "#e3e8f0";

/** Toutes les données d'une journée nécessaires pour construire le body riche. */
export interface DaySyncData {
  /** "YYYY-MM-DD" */
  date: string;
  scores: DailyScores;
  meetings: DailyMeeting[];
  sends: DailySend[];
  /**
   * Sujets des réunions (utile pour afficher des rows lisibles). Indexé par
   * référence d'identité : `subjectByMeeting.get(meeting) -> "Sujet"`.
   * Si absent, un libellé "Réunion HH:MM–HH:MM" est utilisé.
   */
  subjectByMeeting?: Map<DailyMeeting, string>;
}

// ─── IRA header ───────────────────────────────────────────────────────────────
export function iraBand(ira: number): { label: string; color: string } {
  if (ira >= 70) return { label: "Excellente capacité", color: COLOR_POSITIVE };
  if (ira >= 50) return { label: "Capacité modérée", color: COLOR_INTERMEDIATE };
  return { label: "Capacité faible", color: COLOR_NEGATIVE };
}

/** Nb de facteurs ≥ 70 (utilisé pour le subject de l'event). */
export function countFactorsOk(s: DailyScores): number {
  let n = 0;
  if (s.transitions >= 70) n++;
  if (s.concentration >= 70) n++;
  if (s.horaires >= 70) n++;
  if (s.focus >= 70) n++;
  return n;
}

/**
 * Subject de l'event calendrier.
 *   "IRA 78 · 3 facteurs OK"
 *   "IRA 42 · aucun facteur OK"
 */
export function buildEventSubject(scores: DailyScores): string {
  const n = countFactorsOk(scores);
  const suffix =
    n === 0
      ? "aucun facteur OK"
      : `${n} facteur${n > 1 ? "s" : ""} OK`;
  return `IRA ${scores.ira} · ${suffix}`;
}

// ─── Types de la breakdown ─────────────────────────────────────────────────────

type RowCls = "ok" | "ko" | "alert" | "neutral";
type FactorCls = "good" | "warn" | "bad" | "neutral";

interface FactorRowViz {
  label: string;
  val: string;
  cls: RowCls;
}

interface FactorViz {
  name: string;
  summary: string;
  cls: FactorCls;
  score: number;
  rows: FactorRowViz[];
}

function scoreCls(score: number): FactorCls {
  if (score >= 70) return "good";
  if (score >= 50) return "warn";
  return "bad";
}

function colorForRow(cls: RowCls): string {
  switch (cls) {
    case "ok": return COLOR_POSITIVE;
    case "ko": return COLOR_NEGATIVE;
    case "alert": return COLOR_INTERMEDIATE;
    default: return COLOR_ON_SURFACE_MUTED;
  }
}
function colorForFactor(cls: FactorCls): string {
  switch (cls) {
    case "good": return COLOR_POSITIVE;
    case "warn": return COLOR_INTERMEDIATE;
    case "bad": return COLOR_NEGATIVE;
    default: return COLOR_NEUTRAL;
  }
}

// ─── Formatters ───────────────────────────────────────────────────────────────
function pad2(n: number): string {
  return n.toString().padStart(2, "0");
}
function fmtTime(d: Date): string {
  return `${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
}
function fmtDuration(ms: number): string {
  const min = Math.round(ms / 60000);
  if (min < 60) return `${min} min`;
  const h = Math.floor(min / 60);
  const m = min % 60;
  return m === 0 ? `${h}h` : `${h}h${pad2(m)}`;
}
function meetingLabel(m: DailyMeeting, subjectByMeeting?: Map<DailyMeeting, string>): string {
  const subject = subjectByMeeting?.get(m) ?? `Réunion ${fmtTime(m.start)}`;
  return `${fmtTime(m.start)}–${fmtTime(m.end)} ${subject}`;
}

// ─── Facteur 1 : Transitions préservées ───────────────────────────────────────
function vizTransitions(data: DaySyncData, policy: QvctPolicy): FactorViz {
  const { meetings, sends, scores } = data;
  const beforeMs = transBeforeMs(policy);
  const afterMs = transAfterMs(policy);
  const ordered = [...meetings].sort((a, b) => a.start.getTime() - b.start.getTime());
  const rows: FactorRowViz[] = [];
  let ok = 0;
  ordered.forEach((m, i) => {
    const isFirst = i === 0;
    const isLast = i === ordered.length - 1;
    const winBefore = new Date(m.start.getTime() - beforeMs);
    const winAfter = new Date(m.end.getTime() + afterMs);
    const beforeOk = isFirst || beforeMs === 0 ||
      (!meetings.some((o) => o !== m && o.start < m.start && o.end > winBefore) &&
        !sends.some((s) => s.sentAt >= winBefore && s.sentAt < m.start));
    const afterOk = isLast || afterMs === 0 ||
      (!meetings.some((o) => o !== m && o.end > m.end && o.start < winAfter) &&
        !sends.some((s) => s.sentAt > m.end && s.sentAt <= winAfter));
    const isOk = beforeOk || afterOk;
    if (isOk) ok++;
    rows.push({
      label: meetingLabel(m, data.subjectByMeeting),
      val: isOk ? "✓" : "enchaînée",
      cls: isOk ? "ok" : "ko",
    });
  });
  const total = ordered.length;
  const summary = total === 0
    ? "aucune réunion"
    : `${ok}/${total} réunions correctement encadrées`;
  return {
    name: "Transitions préservées",
    summary,
    cls: scoreCls(scores.transitions),
    score: scores.transitions,
    rows,
  };
}

// ─── Facteur 2 : Plages de concentration ──────────────────────────────────────
const FOCUS_MIN_MS = 2 * 60 * 60 * 1000;

function vizConcentration(data: DaySyncData, policy: QvctPolicy): FactorViz {
  const { meetings, sends, scores } = data;
  const [y, mo, dd] = data.date.split("-").map(Number);
  const wStart = new Date(y, mo - 1, dd, policy.workStart.h, policy.workStart.m, 0, 0);
  const wEnd = new Date(y, mo - 1, dd, policy.workEnd.h, policy.workEnd.m, 0, 0);

  const allTimes = [
    ...meetings.flatMap((m) => [m.start, m.end]),
    ...sends.map((s) => s.sentAt),
  ];
  const rows: FactorRowViz[] = [];
  if (allTimes.length === 0) {
    return {
      name: "Plages de concentration",
      summary: "journée sans activité",
      cls: "neutral",
      score: scores.concentration,
      rows: [],
    };
  }
  const first = new Date(Math.min(...allTimes.map((d) => d.getTime())));
  const last = new Date(Math.max(...allTimes.map((d) => d.getTime())));
  const start = first > wStart ? first : wStart;
  const end = last < wEnd ? last : wEnd;

  // Intervalles hors réunion dans la fenêtre
  const nonMeeting: [number, number][] = [];
  const sorted = [...meetings]
    .filter((m) => m.end > start && m.start < end)
    .sort((a, b) => a.start.getTime() - b.start.getTime());
  let cursor = start.getTime();
  for (const m of sorted) {
    const mStart = Math.max(m.start.getTime(), start.getTime());
    const mEnd = Math.min(m.end.getTime(), end.getTime());
    if (cursor < mStart) nonMeeting.push([cursor, mStart]);
    cursor = Math.max(cursor, mEnd);
  }
  if (cursor < end.getTime()) nonMeeting.push([cursor, end.getTime()]);

  // Découpe par envois, ne garder que les segments ≥ 2h
  let plages = 0;
  let totalMs = 0;
  for (const [a, b] of nonMeeting) {
    const cuts = sends
      .map((s) => s.sentAt.getTime())
      .filter((t) => t > a && t < b)
      .sort((x, y) => x - y);
    const points = [a, ...cuts, b];
    for (let i = 0; i < points.length - 1; i++) {
      const segStart = points[i];
      const segEnd = points[i + 1];
      const seg = segEnd - segStart;
      if (seg >= FOCUS_MIN_MS) {
        plages++;
        totalMs += seg;
        rows.push({
          label: `${fmtTime(new Date(segStart))}–${fmtTime(new Date(segEnd))} (${fmtDuration(seg)})`,
          val: "✓",
          cls: "ok",
        });
      }
    }
  }

  const summary = plages === 0
    ? "aucune plage ≥ 2h"
    : `${plages} plage${plages > 1 ? "s" : ""} · ${fmtDuration(totalMs)} de focus`;
  return {
    name: "Plages de concentration",
    summary,
    cls: scoreCls(scores.concentration),
    score: scores.concentration,
    rows,
  };
}

// ─── Facteur 3 : Respect des horaires ─────────────────────────────────────────
function vizHoraires(data: DaySyncData, policy: QvctPolicy): FactorViz {
  const { meetings, sends, scores } = data;
  const wStart = workStartMin(policy);
  const wEnd = workEndMin(policy);
  const startLabel = policy.workStart.m === 0
    ? `${policy.workStart.h}h`
    : `${policy.workStart.h}h${pad2(policy.workStart.m)}`;
  const endLabel = policy.workEnd.m === 0
    ? `${policy.workEnd.h}h`
    : `${policy.workEnd.h}h${pad2(policy.workEnd.m)}`;

  const rows: FactorRowViz[] = [];
  const minutes = (d: Date) => d.getHours() * 60 + d.getMinutes();
  for (const m of meetings) {
    if (minutes(m.start) < wStart || minutes(m.end) > wEnd) {
      rows.push({
        label: meetingLabel(m, data.subjectByMeeting),
        val: minutes(m.start) < wStart ? `avant ${startLabel}` : `après ${endLabel}`,
        cls: "alert",
      });
    }
  }
  for (const s of sends) {
    if (minutes(s.sentAt) < wStart) {
      rows.push({
        label: `Mail envoyé ${fmtTime(s.sentAt)}`,
        val: `avant ${startLabel}`,
        cls: "alert",
      });
    } else if (minutes(s.sentAt) > wEnd) {
      rows.push({
        label: `Mail envoyé ${fmtTime(s.sentAt)}`,
        val: `après ${endLabel}`,
        cls: "alert",
      });
    }
  }

  const summary = rows.length === 0
    ? `conforme à la plage ${startLabel}–${endLabel}`
    : `${rows.length} activité${rows.length > 1 ? "s" : ""} hors plage`;
  return {
    name: "Respect des horaires",
    summary,
    cls: scoreCls(scores.horaires),
    score: scores.horaires,
    rows,
  };
}

// ─── Facteur 4 : Focus en réunion ─────────────────────────────────────────────
function vizFocus(data: DaySyncData): FactorViz {
  const { meetings, sends, scores } = data;
  const real = meetings.filter((m) => m.otherAttendees >= 1);
  const rows: FactorRowViz[] = [];
  let ok = 0;
  for (const m of real) {
    const mailsDuring = sends.filter((s) => s.sentAt >= m.start && s.sentAt <= m.end).length;
    const isOk = mailsDuring === 0;
    if (isOk) ok++;
    rows.push({
      label: meetingLabel(m, data.subjectByMeeting),
      val: isOk ? "✓" : `${mailsDuring} mail${mailsDuring > 1 ? "s" : ""}`,
      cls: isOk ? "ok" : "ko",
    });
  }
  const summary = real.length === 0
    ? "aucune réunion avec participants"
    : `${ok}/${real.length} réunions sans interruption`;
  return {
    name: "Focus en réunion",
    summary,
    cls: scoreCls(scores.focus),
    score: scores.focus,
    rows,
  };
}

// ─── HTML render ──────────────────────────────────────────────────────────────

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function renderFactor(f: FactorViz): string {
  const factorColor = colorForFactor(f.cls);
  const rowsHtml = f.rows
    .map((r) => `
      <table style="width:100%;border-collapse:collapse;"><tr>
        <td style="padding:2px 0 2px 14px;font-size:12px;color:${COLOR_ON_SURFACE_MUTED};line-height:1.4;">${escapeHtml(r.label)}</td>
        <td style="text-align:right;font-size:12px;font-weight:500;color:${colorForRow(r.cls)};white-space:nowrap;padding-left:8px;">${escapeHtml(r.val)}</td>
      </tr></table>`)
    .join("");
  return `
  <div style="padding:10px 0;border-bottom:1px solid ${COLOR_SURFACE_VARIANT};">
    <table style="width:100%;border-collapse:collapse;margin-bottom:4px;"><tr>
      <td style="font-size:13px;font-weight:700;color:${COLOR_ON_SURFACE};">${escapeHtml(f.name)}</td>
      <td style="text-align:right;font-size:12px;font-weight:700;color:${factorColor};white-space:nowrap;padding-left:8px;">${escapeHtml(f.summary)}</td>
    </tr></table>
    ${rowsHtml}
  </div>`;
}

export function buildEventBody(
  data: DaySyncData,
  policy: QvctPolicy = DEFAULT_POLICY
): string {
  const band = iraBand(data.scores.ira);
  const factors: FactorViz[] = [
    vizTransitions(data, policy),
    vizConcentration(data, policy),
    vizHoraires(data, policy),
    vizFocus(data),
  ];

  return `
<div style="font-family:'DM Sans','Segoe UI',sans-serif;color:${COLOR_ON_SURFACE};max-width:520px;">
  <div style="font-size:11px;font-weight:700;color:${COLOR_ON_SURFACE_MUTED};text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;">
    Indice de Récupération Active
  </div>
  <table style="width:100%;border-collapse:collapse;margin-bottom:12px;padding-bottom:10px;border-bottom:1px solid ${COLOR_SURFACE_VARIANT};">
    <tr>
      <td style="width:80px;vertical-align:top;"><span style="font-size:40px;font-weight:800;color:${band.color};line-height:1;">${data.scores.ira}</span></td>
      <td style="vertical-align:middle;color:${band.color};font-size:14px;font-weight:700;padding-left:8px;">${band.label}</td>
    </tr>
  </table>
  ${factors.map(renderFactor).join("")}
  <div style="margin-top:12px;padding-top:10px;border-top:1px solid ${COLOR_SURFACE_VARIANT};font-size:11px;color:${COLOR_ON_SURFACE_MUTED};text-align:center;font-style:italic;">
    Indicateurs définis dans le cadre de la politique QVCT de l'entreprise ·
    <a href="https://arnaud-gr33t.github.io/gr33t-outlook-addin/dashboard.html" style="color:${COLOR_PRIMARY};text-decoration:none;font-weight:600;font-style:normal;">dashboard</a>
  </div>
</div>
`.trim();
}
