/**
 * Extraction des événements qui contribuent à chaque facteur IRA.
 *
 * Utilisé par le drawer "Détail du facteur" : pour chaque facteur, on liste
 * les événements positifs (qui ont compté en faveur du score) et négatifs
 * (qui ont fait baisser le score) sur la fenêtre de 30 jours travaillés.
 *
 * Ce module est purement déclaratif : il consomme les mêmes inputs que le
 * scoring (`DailyMeeting`, `DailySend`, `QvctPolicy`) + une map optionnelle
 * `subjectByMeeting` pour afficher le sujet original des réunions.
 */

import {
  DEFAULT_POLICY,
  transBeforeMs,
  transAfterMs,
  type QvctPolicy,
} from "../config/policy";
import type { DailyMeeting, DailySend } from "./daily";
import type {
  FactorBreakdown,
  FactorDetailsByLevier,
  FactorEvent,
} from "../types/data-contract";

export type { FactorBreakdown, FactorDetailsByLevier, FactorEvent };

export interface DayDetailInput {
  /** ISO YYYY-MM-DD. */
  date: string;
  meetings: DailyMeeting[];
  sends: DailySend[];
  /** Sujets originaux par réunion. Optionnel : fallback "Réunion". */
  subjectByMeeting?: Map<DailyMeeting, string>;
}

// ============================================================
// Helpers
// ============================================================

function isWeekend(iso: string): boolean {
  const [y, m, d] = iso.split("-").map(Number);
  const day = new Date(y, m - 1, d).getDay();
  return day === 0 || day === 6;
}

function fmtTime(d: Date): string {
  const h = d.getHours().toString().padStart(2, "0");
  const m = d.getMinutes().toString().padStart(2, "0");
  return `${h}:${m}`;
}

function setHm(iso: string, h: number, m: number): Date {
  const [yy, mm, dd] = iso.split("-").map(Number);
  const d = new Date(yy, mm - 1, dd);
  d.setHours(h, m, 0, 0);
  return d;
}

function meetingTitle(
  m: DailyMeeting,
  subjects?: Map<DailyMeeting, string>
): string {
  const s = subjects?.get(m);
  return s && s.trim() !== "" ? s : "Réunion";
}

function sortByDateDesc(a: FactorEvent, b: FactorEvent): number {
  return b.start.getTime() - a.start.getTime();
}

// ============================================================
// Factor 1 — Transitions
// ============================================================

function breakdownTransitions(
  days: DayDetailInput[],
  policy: QvctPolicy
): FactorBreakdown {
  const beforeMs = transBeforeMs(policy);
  const afterMs = transAfterMs(policy);
  const beforeMin = policy.transBeforeMin;
  const afterMin = policy.transAfterMin;
  const positives: FactorEvent[] = [];
  const negatives: FactorEvent[] = [];

  for (const day of days) {
    if (isWeekend(day.date)) continue;
    if (day.meetings.length === 0) continue;
    const ordered = [...day.meetings].sort(
      (a, b) => a.start.getTime() - b.start.getTime()
    );
    const hasMeetingIn = (a: Date, b: Date, exclude: DailyMeeting) => {
      for (const mm of day.meetings) {
        if (mm === exclude) continue;
        if (mm.start < b && mm.end > a) return true;
      }
      return false;
    };

    ordered.forEach((m, i) => {
      const isFirst = i === 0;
      const isLast = i === ordered.length - 1;
      const beforeOk =
        isFirst ||
        beforeMs === 0 ||
        !hasMeetingIn(new Date(m.start.getTime() - beforeMs), m.start, m);
      const afterOk =
        isLast ||
        afterMs === 0 ||
        !hasMeetingIn(m.end, new Date(m.end.getTime() + afterMs), m);

      const ev: FactorEvent = {
        date: day.date,
        start: m.start,
        time: fmtTime(m.start),
        endTime: fmtTime(m.end),
        title: meetingTitle(m, day.subjectByMeeting),
        detail: "",
        kind: "negative",
      };

      // Nouvelle règle : OK uniquement si AUCUNE réunion trop proche
      // ni avant ni après.
      if (beforeOk && afterOk) {
        ev.kind = "positive";
        if (isFirst && isLast) ev.detail = "Seule réunion du jour";
        else if (isFirst) ev.detail = `Transition ≥ ${afterMin} min après`;
        else if (isLast) ev.detail = `Transition ≥ ${beforeMin} min avant`;
        else ev.detail = `Transitions ≥ ${beforeMin} min avant et après`;
        positives.push(ev);
      } else {
        // KO : au moins un côté est trop proche d'une autre réunion
        if (!beforeOk && !afterOk) {
          ev.detail = `Enchaînée des deux côtés (< ${beforeMin}/${afterMin} min)`;
        } else if (!beforeOk) {
          ev.detail = `Enchaînée à la réunion précédente (< ${beforeMin} min)`;
        } else {
          ev.detail = `Enchaînée à la réunion suivante (< ${afterMin} min)`;
        }
        negatives.push(ev);
      }
    });
  }

  positives.sort(sortByDateDesc);
  negatives.sort(sortByDateDesc);
  return { positives, negatives };
}

// ============================================================
// Factor 2 — Concentration
// ============================================================

const FOCUS_DEEP_MS = 2 * 60 * 60 * 1000;
const FOCUS_MIN_MS = 30 * 60 * 1000;

function breakdownConcentration(
  days: DayDetailInput[],
  policy: QvctPolicy
): FactorBreakdown {
  const positives: FactorEvent[] = [];
  const negatives: FactorEvent[] = [];

  for (const day of days) {
    if (isWeekend(day.date)) continue;
    const wStart = setHm(day.date, policy.workStart.h, policy.workStart.m);
    const wEnd = setHm(day.date, policy.workEnd.h, policy.workEnd.m);
    const allTimes: Date[] = [];
    for (const m of day.meetings) allTimes.push(m.start, m.end);
    for (const s of day.sends) allTimes.push(s.sentAt);
    if (allTimes.length === 0) continue;

    const first = new Date(Math.min(...allTimes.map((d) => d.getTime())));
    const last = new Date(Math.max(...allTimes.map((d) => d.getTime())));
    const start = first > wStart ? first : wStart;
    const end = last < wEnd ? last : wEnd;
    if (end.getTime() <= start.getTime()) continue;

    const mInWindow = day.meetings.filter(
      (m) => m.end > start && m.start < end
    );
    const sInWindow = day.sends.filter(
      (s) => s.sentAt >= start && s.sentAt < end
    );

    // Construire les intervalles hors réunion
    const sortedM = [...mInWindow].sort(
      (a, b) => a.start.getTime() - b.start.getTime()
    );
    let cursor = start.getTime();
    const nonMeeting: [number, number][] = [];
    for (const m of sortedM) {
      const ms = Math.max(m.start.getTime(), start.getTime());
      const me = Math.min(m.end.getTime(), end.getTime());
      if (cursor < ms) nonMeeting.push([cursor, ms]);
      cursor = Math.max(cursor, me);
    }
    if (cursor < end.getTime()) nonMeeting.push([cursor, end.getTime()]);

    // Couper par mails → segments candidats
    for (const [a, b] of nonMeeting) {
      const cuts = sInWindow
        .map((s) => s.sentAt.getTime())
        .filter((t) => t > a && t < b)
        .sort((x, y) => x - y);
      const points = [a, ...cuts, b];
      for (let i = 0; i < points.length - 1; i++) {
        const segStart = new Date(points[i]);
        const segEnd = new Date(points[i + 1]);
        const segMs = segEnd.getTime() - segStart.getTime();
        if (segMs < FOCUS_MIN_MS) continue;
        const ev: FactorEvent = {
          date: day.date,
          start: segStart,
          time: fmtTime(segStart),
          endTime: fmtTime(segEnd),
          title: `Plage ${fmtTime(segStart)}–${fmtTime(segEnd)}`,
          detail: "",
          kind: "positive",
        };
        if (segMs >= FOCUS_DEEP_MS) {
          ev.detail = `Focus profond (${formatDur(segMs)})`;
          ev.kind = "positive";
          positives.push(ev);
        } else {
          ev.detail = `Plage trop courte (${formatDur(segMs)}) — interrompue`;
          ev.kind = "negative";
          negatives.push(ev);
        }
      }
    }
  }

  positives.sort(sortByDateDesc);
  negatives.sort(sortByDateDesc);
  return { positives, negatives };
}

function formatDur(ms: number): string {
  const min = Math.round(ms / 60_000);
  if (min < 60) return `${min}min`;
  const h = Math.floor(min / 60);
  const r = min % 60;
  if (r === 0) return `${h}h`;
  return `${h}h${r.toString().padStart(2, "0")}`;
}

// ============================================================
// Factor 3 — Horaires
// ============================================================

function breakdownHoraires(
  days: DayDetailInput[],
  policy: QvctPolicy
): FactorBreakdown {
  const positives: FactorEvent[] = [];
  const negatives: FactorEvent[] = [];

  for (const day of days) {
    const weekend = isWeekend(day.date);
    const wStart = setHm(day.date, policy.workStart.h, policy.workStart.m);
    const wEnd = setHm(day.date, policy.workEnd.h, policy.workEnd.m);
    let dayHasOverflow = false;

    for (const m of day.meetings) {
      const out = weekend || m.start < wStart || m.end > wEnd;
      if (out) {
        dayHasOverflow = true;
        negatives.push({
          date: day.date,
          start: m.start,
          time: fmtTime(m.start),
          endTime: fmtTime(m.end),
          title: meetingTitle(m, day.subjectByMeeting),
          detail: weekend
            ? "Réunion un week-end"
            : "Réunion hors plage de travail",
          kind: "negative",
        });
      }
    }
    for (const s of day.sends) {
      const out = weekend || s.sentAt < wStart || s.sentAt > wEnd;
      if (out) {
        dayHasOverflow = true;
        negatives.push({
          date: day.date,
          start: s.sentAt,
          time: fmtTime(s.sentAt),
          title: "Mail envoyé",
          detail: weekend
            ? "Mail envoyé un week-end"
            : "Mail envoyé hors plage de travail",
          kind: "negative",
        });
      }
    }

    // Positif : 1 entrée par jour respecté (si activité)
    if (!dayHasOverflow && (day.meetings.length > 0 || day.sends.length > 0)) {
      positives.push({
        date: day.date,
        start: wStart,
        time: "",
        title: "Journée dans les horaires",
        detail: "Aucune activité hors plage",
        kind: "positive",
      });
    }
  }

  positives.sort(sortByDateDesc);
  negatives.sort(sortByDateDesc);
  return { positives, negatives };
}

// ============================================================
// Factor 4 — Focus en réunion
// ============================================================

function breakdownFocus(days: DayDetailInput[]): FactorBreakdown {
  const positives: FactorEvent[] = [];
  const negatives: FactorEvent[] = [];

  for (const day of days) {
    if (isWeekend(day.date)) continue;
    const real = day.meetings.filter((m) => m.otherAttendees >= 1);
    for (const m of real) {
      const interrupters = day.sends.filter(
        (s) => s.sentAt >= m.start && s.sentAt <= m.end
      );
      const ev: FactorEvent = {
        date: day.date,
        start: m.start,
        time: fmtTime(m.start),
        endTime: fmtTime(m.end),
        title: meetingTitle(m, day.subjectByMeeting),
        detail: "",
        kind: "positive",
      };
      if (interrupters.length === 0) {
        ev.detail = "Focus préservé";
        positives.push(ev);
      } else {
        const times = interrupters.map((s) => fmtTime(s.sentAt)).join(", ");
        const n = interrupters.length;
        ev.detail = `Interrompue par ${n} mail${n > 1 ? "s" : ""} (${times})`;
        ev.kind = "negative";
        negatives.push(ev);
      }
    }
  }

  positives.sort(sortByDateDesc);
  negatives.sort(sortByDateDesc);
  return { positives, negatives };
}

// ============================================================
// Entry point
// ============================================================

export function buildFactorDetails(
  days: DayDetailInput[],
  policy: QvctPolicy = DEFAULT_POLICY
): FactorDetailsByLevier {
  return {
    transitions: breakdownTransitions(days, policy),
    concentration: breakdownConcentration(days, policy),
    horaires: breakdownHoraires(days, policy),
    focus_reunion: breakdownFocus(days),
  };
}
