import * as React from "react";
import styles from "./MainPage.module.css";
import { useDashboardData } from "../../rythme/data/data-provider";
import { THEMES, THEME_ORDER } from "../data/themes";
import { recosByTheme } from "../data/recos";
import { useStatuses } from "../data/statusStore";
import { pickPriorities } from "../scoring/match";
import { RecoCard } from "../components/RecoCard/RecoCard";
import { ThemeTile } from "../components/ThemeTile/ThemeTile";

/**
 * Écran principal de l'onglet Accompagnement.
 *
 * Layout (largeur max 1232px) :
 *   - Intro : eyebrow + titre + sous-titre + carte mini-IRA à droite
 *   - Section "Vos priorités cette semaine" : 3 RecoCard contextualisées
 *   - Section "Explorer toutes les recommandations" : 4 ThemeTile
 *   - Footer méthodo (sources)
 */
export const MainPage: React.FC = () => {
  const data = useDashboardData();
  const { statuses, setStatus } = useStatuses();

  const priorities = React.useMemo(() => {
    if (!data.matchSignals) return [];
    return pickPriorities({ ...data.matchSignals, statuses });
  }, [data.matchSignals, statuses]);

  return (
    <div className={styles.root}>
      <section className={styles.intro}>
        <div>
          <div className={styles.eyebrow}>Votre parcours de sensibilisation</div>
          <h2 className={styles.h2}>
            13 recommandations issues des études Lecko, sélectionnées selon votre
            rythme.
          </h2>
          <p className={styles.p}>
            Mises à jour chaque semaine en fonction de votre score IRA. Vous
            gardez la main : explorez librement les thématiques en dessous.
          </p>
        </div>
        <div className={styles.iraMini}>
          <span className={styles.eyebrow}>Votre IRA</span>
          <div className={styles.iraValueRow}>
            <span className={styles.iraValue}>{data.ira.value}</span>
            <span className={styles.iraOf}>/100</span>
            {data.ira.delta !== 0 && (
              <span
                className={styles.iraDelta}
                style={{
                  color:
                    data.ira.delta < 0
                      ? "var(--gr33t-pink)"
                      : "var(--gr33t-green)",
                }}
              >
                {data.ira.delta > 0 ? "+" : ""}
                {data.ira.delta} pts
              </span>
            )}
          </div>
          <span className={styles.iraSub}>{data.ira.label}</span>
        </div>
      </section>

      <section className={styles.section}>
        <div className={styles.secHead}>
          <h3 className={styles.h3}>Vos priorités cette semaine</h3>
          <span className={styles.secSub}>
            Choisies à partir de vos indicateurs IRA. Renouvelées chaque lundi.
          </span>
        </div>
        {priorities.length > 0 ? (
          <div className={styles.priorityGrid}>
            {priorities.map((p) => (
              <RecoCard
                key={p.reco.id}
                reco={p.reco}
                why={p.why}
                status={statuses.get(p.reco.id) ?? "new"}
                onMark={setStatus}
              />
            ))}
          </div>
        ) : (
          <div className={styles.emptyState}>
            Cette semaine, vos indicateurs sont dans le vert. Profitez-en pour
            explorer librement les recommandations ci-dessous.
          </div>
        )}
      </section>

      <section className={styles.section}>
        <div className={styles.secHead}>
          <h3 className={styles.h3}>Explorer toutes les recommandations</h3>
          <span className={styles.secSub}>
            13 fiches, regroupées par thématique. Naviguez à votre rythme.
          </span>
        </div>
        <div className={styles.themesGrid}>
          {THEME_ORDER.map((k) => (
            <ThemeTile
              key={k}
              theme={THEMES[k]}
              recos={recosByTheme(k)}
              statuses={statuses}
            />
          ))}
        </div>
      </section>

      <footer className={styles.meta}>
        <span>
          Sources : Lecko, Etat de l'art QVCT 2026 · Bruit organisationnel 2026
          · Lecko x Ipsos 2023 · Lecko x Cog'X 2024.
        </span>
      </footer>
    </div>
  );
};
