import * as React from "react";
import { Routes, Route } from "react-router-dom";
import { MainPage } from "./routes/MainPage";
import { ThemePage } from "./routes/ThemePage";
import { DetailPage } from "./routes/DetailPage";

/**
 * Racine de l'onglet Accompagnement.
 *
 * Sous-routes (sous le préfixe `/accompagnement` du router parent) :
 *   - /                    → MainPage (priorités + tuiles thématiques)
 *   - /theme/:slug         → ThemePage (vue thématique déroulée)
 *   - /reco/:id            → DetailPage (page détail d'une reco)
 *
 * Le wrapper `.acc-scope` active la palette `--gr33t-*` et la font Inter Tight
 * uniquement dans cette zone, sans impacter les autres onglets.
 */
export const AccompagnementTab: React.FC = () => {
  return (
    <div className="acc-scope">
      <Routes>
        <Route path="/" element={<MainPage />} />
        <Route path="/theme/:slug" element={<ThemePage />} />
        <Route path="/reco/:id" element={<DetailPage />} />
      </Routes>
    </div>
  );
};
