/**
 * Sync automatique des scores IRA v1.1 vers des events all-day dans le
 * calendrier "Gr33t Recovery". Appelé en fire-and-forget au démarrage
 * du dashboard, throttlé à 1×/24h.
 *
 * Idempotence : on matche les events existants par **date locale**. Si
 * un event Gr33t all-day existe déjà pour un jour donné → PATCH du
 * subject / body / extension. Sinon → POST.
 *
 * L'utilisateur qui supprime manuellement un event → recréation au
 * prochain run (option "dashboard = source of truth").
 *
 * Extension : `com.gr33t.ira` (schemaVersion 1) — distincte de
 * `com.gr33t.recovery` utilisée par le TaskPane legacy (v1). Cohabitation
 * propre, pas de collision.
 */
import type { DailyScores } from "../dashboard/rythme/scoring/daily";
import type { QvctPolicy } from "../dashboard/rythme/config/policy";
import {
  graphFetch,
  findOrCreateGr33tRecoveryCalendar,
  ensureGr33tCategories,
  CATEGORY_FOCUS_DEEP,
  CATEGORY_FOCUS_PLAGE,
} from "./graphHttp";
import {
  buildEventSubject,
  buildEventBody,
  type DaySyncData,
} from "./scoreEventBody";
import { computeFocusBlocks, formatDuration, type FocusBlock } from "./focusBlocks";

export type { DaySyncData } from "./scoreEventBody";

export const IRA_EXTENSION_NAME = "com.gr33t.ira";
export const SYNC_LOCALSTORAGE_KEY = "gr33t.lastSync.v1";
const SYNC_THROTTLE_MS = 24 * 60 * 60 * 1000; // 24h

export interface SyncResult {
  /** true si la sync a effectivement tourné (pas throttlée). */
  ran: boolean;
  /** Nb d'events all-day IRA créés (POST). */
  created: number;
  /** Nb d'events all-day IRA mis à jour (PATCH). */
  updated: number;
  /** Nb de jours ignorés (score absent / erreur par jour). */
  skipped: number;
  /** Nb de focus events créés. */
  focusCreated: number;
  /** Nb de focus events mis à jour (PATCH sur start identique). */
  focusUpdated: number;
  /** Nb de focus events supprimés (n'ayant plus de plage correspondante). */
  focusDeleted: number;
  /** Erreurs bloquantes globales (ex: 403 scope manquant). */
  error?: string;
}

function pad2(n: number): string {
  return n.toString().padStart(2, "0");
}

function toIsoDate(d: Date): string {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`;
}

function shiftDays(d: Date, days: number): Date {
  const r = new Date(d);
  r.setDate(d.getDate() + days);
  return r;
}

// ─────────────────────────────────────────────────────────────────────
// Throttle
// ─────────────────────────────────────────────────────────────────────

/** true si la dernière sync date de moins de 24h. */
export function isThrottled(
  now: number = Date.now(),
  storage: Storage | undefined = typeof localStorage !== "undefined"
    ? localStorage
    : undefined
): boolean {
  if (!storage) return false;
  const raw = storage.getItem(SYNC_LOCALSTORAGE_KEY);
  if (!raw) return false;
  const last = Date.parse(raw);
  if (Number.isNaN(last)) return false;
  return now - last < SYNC_THROTTLE_MS;
}

function markSynced(now: number = Date.now()): void {
  if (typeof localStorage === "undefined") return;
  try {
    localStorage.setItem(SYNC_LOCALSTORAGE_KEY, new Date(now).toISOString());
  } catch {
    // Quota / privacy mode — on ignore silencieusement
  }
}

// ─────────────────────────────────────────────────────────────────────
// Graph payload helpers
// ─────────────────────────────────────────────────────────────────────

interface ExistingEvent {
  id: string;
  /** ISO "YYYY-MM-DD" extrait de start.dateTime */
  date: string;
}

interface GraphEvent {
  id: string;
  isAllDay?: boolean;
  start?: { dateTime?: string };
  end?: { dateTime?: string };
  subject?: string;
  categories?: string[];
}

function toGraphDateTime(d: Date): string {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}T${pad2(d.getHours())}:${pad2(d.getMinutes())}:${pad2(d.getSeconds())}`;
}

interface ExistingByWindow {
  /** All-day events par date ISO (pour les events de score). */
  allDay: Map<string, ExistingEvent>;
  /** Focus events Gr33t-managés (taggés par catégorie), groupés par date ISO. */
  focusByDate: Map<string, GraphEvent[]>;
}

/**
 * Récupère en un seul appel les events de la fenêtre [start, end] :
 *   - all-day → matching par date ISO pour les events de score
 *   - timed avec catégorie Gr33t (Focus profond / Plage focus) → matching par start
 */
async function fetchExistingEvents(
  token: string,
  calendarId: string,
  startIso: string,
  endIso: string
): Promise<ExistingByWindow> {
  const resp = await graphFetch<{ value: GraphEvent[] }>(
    token,
    `/me/calendars/${calendarId}/calendarView` +
      `?startDateTime=${startIso}T00:00:00` +
      `&endDateTime=${endIso}T00:00:00` +
      `&$select=id,isAllDay,start,end,subject,categories` +
      `&$top=500`
  );
  const allDay = new Map<string, ExistingEvent>();
  const focusByDate = new Map<string, GraphEvent[]>();
  for (const ev of resp.value ?? []) {
    const dt = ev.start?.dateTime;
    if (!dt) continue;
    const date = dt.slice(0, 10);
    if (ev.isAllDay) {
      if (!allDay.has(date)) allDay.set(date, { id: ev.id, date });
      continue;
    }
    const cats = ev.categories ?? [];
    if (cats.includes(CATEGORY_FOCUS_DEEP) || cats.includes(CATEGORY_FOCUS_PLAGE)) {
      const list = focusByDate.get(date) ?? [];
      list.push(ev);
      focusByDate.set(date, list);
    }
  }
  return { allDay, focusByDate };
}

function eventBodyFor(
  isoDate: string,
  data: DaySyncData,
  policy: QvctPolicy
): Record<string, unknown> {
  const subject = buildEventSubject(data.scores);
  const body = buildEventBody(data, policy);
  const next = new Date(isoDate);
  next.setDate(next.getDate() + 1);
  const nextIso = toIsoDate(next);
  return {
    subject,
    body: { contentType: "html", content: body },
    start: { dateTime: `${isoDate}T00:00:00`, timeZone: "Europe/Paris" },
    end: { dateTime: `${nextIso}T00:00:00`, timeZone: "Europe/Paris" },
    isAllDay: true,
    showAs: "free",
    isReminderOn: false,
  };
}

function extensionPayload(scores: DailyScores, isoDate: string): Record<string, unknown> {
  return {
    "@odata.type": "microsoft.graph.openTypeExtension",
    extensionName: IRA_EXTENSION_NAME,
    schemaVersion: 1,
    source: "dashboard-v1.1",
    date: isoDate,
    scores,
  };
}

// ─────────────────────────────────────────────────────────────────────
// Focus events helpers
// ─────────────────────────────────────────────────────────────────────

function focusEventSubject(block: FocusBlock): string {
  const duration = formatDuration(block.durationMs);
  return block.kind === "deep"
    ? `Focus profond (${duration})`
    : `Focus (${duration})`;
}

function focusEventPayload(block: FocusBlock): Record<string, unknown> {
  const category =
    block.kind === "deep" ? CATEGORY_FOCUS_DEEP : CATEGORY_FOCUS_PLAGE;
  return {
    subject: focusEventSubject(block),
    start: { dateTime: toGraphDateTime(block.start), timeZone: "Europe/Paris" },
    end: { dateTime: toGraphDateTime(block.end), timeZone: "Europe/Paris" },
    showAs: "free",
    isReminderOn: false,
    categories: [category],
  };
}

/**
 * Sync les focus events d'une journée donnée.
 * Stratégie : matching par start exact. Existants non-matchés → DELETE.
 * Nouveaux → POST. Matchés → PATCH (pour rafraîchir durée/catégorie).
 */
async function syncFocusForDay(
  token: string,
  calendarId: string,
  isoDate: string,
  targets: FocusBlock[],
  existing: GraphEvent[],
  result: SyncResult
): Promise<void> {
  const existingByStartMs = new Map<number, GraphEvent>();
  for (const ev of existing) {
    if (ev.start?.dateTime) {
      existingByStartMs.set(new Date(ev.start.dateTime).getTime(), ev);
    }
  }
  const targetStartMs = new Set(targets.map((t) => t.start.getTime()));

  // DELETE existants non-matchés
  for (const [ms, ev] of existingByStartMs) {
    if (!targetStartMs.has(ms)) {
      try {
        await graphFetch(token, `/me/events/${ev.id}`, { method: "DELETE" });
        result.focusDeleted++;
      } catch {
        // non fatal
      }
    }
  }
  // POST / PATCH cibles
  for (const t of targets) {
    const existingEv = existingByStartMs.get(t.start.getTime());
    const payload = focusEventPayload(t);
    try {
      if (existingEv) {
        await graphFetch(token, `/me/events/${existingEv.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
        result.focusUpdated++;
      } else {
        await graphFetch(token, `/me/calendars/${calendarId}/events`, {
          method: "POST",
          body: JSON.stringify(payload),
        });
        result.focusCreated++;
      }
    } catch {
      // non fatal, on continue sur les autres blocs
    }
  }
}

// ─────────────────────────────────────────────────────────────────────
// Sync principal
// ─────────────────────────────────────────────────────────────────────

/**
 * Synchronise les scores des 30 derniers jours (J-1 → J-30) vers le
 * calendrier Gr33t Recovery. Throttlé à 1×/24h.
 *
 * @param token Bearer Graph valide
 * @param scoresByDate map ISO→DailyScores (déjà calculée par le dashboard)
 * @param today Date de référence (minuit local). Défaut = maintenant.
 * @param force  Ignore le throttle (tests / bouton debug).
 */
export async function syncScoreEvents(
  token: string,
  dataByDate: Map<string, DaySyncData>,
  policy: QvctPolicy,
  today: Date = new Date(),
  force: boolean = false
): Promise<SyncResult> {
  if (!force && isThrottled()) {
    return {
      ran: false, created: 0, updated: 0, skipped: 0,
      focusCreated: 0, focusUpdated: 0, focusDeleted: 0,
    };
  }

  const result: SyncResult = {
    ran: true, created: 0, updated: 0, skipped: 0,
    focusCreated: 0, focusUpdated: 0, focusDeleted: 0,
  };

  // Fenêtre : J-30 → J-1 inclus
  const startDate = shiftDays(today, -30);
  const endDate = today; // borne exclusive Graph : J (exclu)
  const startIso = toIsoDate(startDate);
  const endIso = toIsoDate(endDate);

  let calendarId: string;
  let existing: ExistingByWindow;
  try {
    // S'assure que les 2 master categories Gr33t existent (idempotent)
    await ensureGr33tCategories(token).catch(() => undefined);
    calendarId = await findOrCreateGr33tRecoveryCalendar(token);
    existing = await fetchExistingEvents(token, calendarId, startIso, endIso);
  } catch (err) {
    const e = err as { status?: number; message?: string };
    if (e.status === 401) {
      return { ...result, ran: false, error: "auth" };
    }
    if (e.status === 403) {
      result.error = "Scope Calendars.ReadWrite requis (relogin nécessaire).";
      return result;
    }
    result.error = e.message ?? String(err);
    return result;
  }

  // Parcourt J-30 → J-1 (30 jours) et upsert chaque jour avec un score
  for (let offset = 1; offset <= 30; offset++) {
    const day = shiftDays(today, -offset);
    const iso = toIsoDate(day);
    const dayData = dataByDate.get(iso);
    if (!dayData) {
      result.skipped++;
      continue;
    }

    const existingEv = existing.allDay.get(iso);
    const payload = eventBodyFor(iso, dayData, policy);
    const ext = extensionPayload(dayData.scores, iso);

    try {
      if (existingEv) {
        await graphFetch(token, `/me/events/${existingEv.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
        await upsertExtension(token, existingEv.id, ext);
        result.updated++;
      } else {
        await graphFetch(token, `/me/calendars/${calendarId}/events`, {
          method: "POST",
          body: JSON.stringify({ ...payload, extensions: [ext] }),
        });
        result.created++;
      }
    } catch {
      result.skipped++;
    }

    // Sync des focus events du jour (blocs ≥ 30 min)
    const blocks = computeFocusBlocks(iso, dayData.meetings, dayData.sends, policy);
    const existingFocus = existing.focusByDate.get(iso) ?? [];
    await syncFocusForDay(token, calendarId, iso, blocks, existingFocus, result);
  }

  // Ne marque "synced" que si au moins 1 écriture réussie
  if (
    result.created + result.updated + result.focusCreated + result.focusUpdated >
    0
  ) {
    markSynced();
  }
  return result;
}

async function upsertExtension(
  token: string,
  eventId: string,
  ext: Record<string, unknown>
): Promise<void> {
  try {
    await graphFetch(
      token,
      `/me/events/${eventId}/extensions/${IRA_EXTENSION_NAME}`,
      { method: "PATCH", body: JSON.stringify(ext) }
    );
  } catch (err) {
    const e = err as { status?: number };
    if (e.status === 404) {
      // Extension absente → POST
      await graphFetch(token, `/me/events/${eventId}/extensions`, {
        method: "POST",
        body: JSON.stringify(ext),
      });
      return;
    }
    throw err;
  }
}
