import * as React from "react";
import { useNavigate } from "react-router-dom";
import styles from "./ThemeTile.module.css";
import type { Theme } from "../../data/themes";
import type { Reco } from "../../data/recos";
import type { RecoStatus } from "../../data/statusStore";

export interface ThemeTileProps {
  theme: Theme;
  recos: Reco[];
  /** Map id → status pour cocher les essayées dans la liste interne. */
  statuses: Map<number, RecoStatus>;
}

/**
 * Tuile thématique. Cliquable → navigue vers `/accompagnement/theme/:slug`.
 * Si `theme.comingSoon`, la tuile est affichée mais non cliquable.
 */
export const ThemeTile: React.FC<ThemeTileProps> = ({
  theme,
  recos,
  statuses,
}) => {
  const navigate = useNavigate();
  const done = recos.filter((r) => statuses.get(r.id) === "essayee").length;
  const isDisabled = !!theme.comingSoon;

  const onClick = () => {
    if (!isDisabled) navigate(`/accompagnement/theme/${theme.key}`);
  };

  return (
    <div
      className={`${styles.tile} ${isDisabled ? styles.disabled : ""}`}
      onClick={onClick}
      role={isDisabled ? undefined : "button"}
      tabIndex={isDisabled ? undefined : 0}
      onKeyDown={(e) => {
        if (!isDisabled && e.key === "Enter") onClick();
      }}
      aria-disabled={isDisabled}
    >
      <div className={styles.head}>
        <span
          className={styles.dotLg}
          style={{ background: theme.colorVar }}
          aria-hidden
        />
        <div className={styles.title}>{theme.label}</div>
      </div>
      <div className={styles.count}>
        {isDisabled
          ? "Bientôt disponible"
          : `${recos.length} fiche${recos.length > 1 ? "s" : ""}${
              done ? ` · ${done} essayée${done > 1 ? "s" : ""}` : ""
            }`}
      </div>

      {!isDisabled && (
        <ul className={styles.list}>
          {recos.slice(0, 3).map((r) => {
            const isDone = statuses.get(r.id) === "essayee";
            return (
              <li key={r.id} className={styles.item}>
                <span
                  className={`${styles.tick} ${isDone ? styles.tickDone : ""}`}
                  aria-hidden
                >
                  {isDone && (
                    <span className="material-symbols-rounded">check</span>
                  )}
                </span>
                <span className={isDone ? styles.itemDone : ""}>{r.title}</span>
              </li>
            );
          })}
          {recos.length > 3 && (
            <li className={styles.itemMore}>+ {recos.length - 3} autres</li>
          )}
        </ul>
      )}

      <div className={styles.cta}>
        {isDisabled ? (
          <span style={{ color: "var(--gr33t-slate-2)" }}>—</span>
        ) : (
          <>
            Explorer
            <span className="material-symbols-rounded" aria-hidden>
              arrow_forward
            </span>
          </>
        )}
      </div>
    </div>
  );
};
