/**
 * Moteur de matching — sélection des 3 recommandations prioritaires.
 *
 * Spec : `regles_matching_recommandations.md` (Lecko / Gr33t).
 *
 * Inputs : signaux observés sur la **semaine précédente** (S-1, lun→ven)
 * + historique court (3-4 sem) pour la chronicité + prévisionnel S+1.
 *
 * Pipeline :
 *   1. Évaluer chaque règle → liste des candidates avec leur `gap` au seuil
 *   2. Filtrer les recos avec statut "essayee" ou "pasPourMoi"
 *   3. Trier par `gap` décroissant (principe 1), puis par `impact/effort`
 *      décroissant (principe 2)
 *   4. Garantir la diversité éditoriale (principe 4) : dans le top 3, pas
 *      plus d'une reco par thème (sauf si pas assez de candidates)
 *   5. Retourner top 3 avec payload `why` pour l'UI
 *
 * Principe 3 (anti-répétition par historique) : non implémenté en v0.
 *
 * Recos NON-prioritisables en v0 (signaux non captés) :
 *   - 4 (visios consécutives)
 *   - 10, 11, 15, 16 (chats, copies, stockage, manager) — déjà retirées de
 *     la bibliothèque, donc absentes de RECOS
 */

import { RECOS, type Reco } from "../data/recos";
import type { ThemeKey } from "../data/themes";
import type { RecoStatus } from "../data/statusStore";
import type {
  MatchSignals,
  WeeklyFactorScores,
} from "../../rythme/types/data-contract";

export type { MatchSignals, WeeklyFactorScores };

/** Inputs complets du matching = signaux + statuts utilisateur. */
export interface MatchInputs extends MatchSignals {
  statuses: Map<number, RecoStatus>;
}

/**
 * Payload "Pourquoi cette reco" attaché à une priorité, pour alimenter
 * le ruban contextuel et le mini-graph dans l'UI.
 */
export interface WhyPayload {
  /** Texte court affiché dans le ruban (ex: "59% de débordements horaires"). */
  label: string;
  /** Valeur observée (typiquement 0-100, parfois en heures). */
  value: number;
  /** Borne haute du graphe (100 par défaut, 30 ou 40 pour les heures). */
  max: number;
  /** Seuil cible (au-dessus → mauvais, sauf si `inverse`). */
  threshold: number;
  /** Si vrai, le mauvais côté est sous le seuil (ex: plages de concentration). */
  inverse?: boolean;
  /** Catégorie sémantique (utile pour le wording UI). */
  kind: WhyKind;
}

export type WhyKind =
  | "multitache"
  | "enchainees"
  | "mtreunion"
  | "debord"
  | "plages"
  | "volume"
  | "anticipation"
  | "chronique";

/** Une priorité = la reco + son payload `why`. */
export interface Priority {
  reco: Reco;
  why: WhyPayload;
}

// ============================================================
// Règles : reco → trigger (évaluation)
// ============================================================

/**
 * Pour chaque reco, retourne le `WhyPayload` si la règle se déclenche,
 * sinon `null`. Le `gap` (écart au seuil) est calculé en aval (cf. `score`).
 */
type RuleEvaluator = (i: MatchInputs) => WhyPayload | null;

const RULES: Record<number, RuleEvaluator> = {
  // --- Réunions enchaînées (= 100 - transitions) ---
  3: (i) => triggerEnchainees(i),
  8: (i) => triggerEnchainees(i),

  // --- Multitâche permanent (= 100 - concentration) ---
  1: (i) => triggerMultitache(i),
  7: (i) => triggerMultitache(i),

  // --- Plages de concentration (= concentration directement, inverse) ---
  12: (i) => triggerPlages(i),

  // --- Multitâche en réunion (= 100 - focus) ---
  5: (i) => triggerMtreunion(i),

  // --- Débordements horaires (= 100 - horaires) ---
  6: (i) => triggerDebord(i),
  9: (i) => triggerDebord(i),

  // --- Volume de réunions (heures) ---
  2: (i) => triggerVolume(i),
  17: (i) => triggerVolume(i),

  // --- Anticipation (S+1 vs moyenne 4 sem) ---
  13: (i) => triggerAnticipation(i),

  // --- Chronicité (débordements > 50% sur 3 sem) ---
  14: (i) => triggerChronique(i),

  // Reco 4 : pas de règle implémentée en v0 (visios consécutives non détectées)
};

function triggerEnchainees(i: MatchInputs): WhyPayload | null {
  if (!i.weekPrev) return null;
  const v = 100 - i.weekPrev.transitions;
  if (v <= 20) return null;
  return {
    label: `${v}% de réunions enchaînées`,
    value: v,
    max: 100,
    threshold: 20,
    kind: "enchainees",
  };
}

function triggerMultitache(i: MatchInputs): WhyPayload | null {
  if (!i.weekPrev) return null;
  const v = 100 - i.weekPrev.concentration;
  if (v <= 25) return null;
  return {
    label: `${v}% de multitâche permanent`,
    value: v,
    max: 100,
    threshold: 25,
    kind: "multitache",
  };
}

function triggerPlages(i: MatchInputs): WhyPayload | null {
  if (!i.weekPrev) return null;
  const v = i.weekPrev.concentration;
  if (v >= 60) return null;
  return {
    label: `${v}% de plages de concentration`,
    value: v,
    max: 100,
    threshold: 60,
    inverse: true,
    kind: "plages",
  };
}

function triggerMtreunion(i: MatchInputs): WhyPayload | null {
  if (!i.weekPrev) return null;
  const v = 100 - i.weekPrev.focus;
  if (v <= 15) return null;
  return {
    label: `${v}% de multitâche en réunion`,
    value: v,
    max: 100,
    threshold: 15,
    kind: "mtreunion",
  };
}

function triggerDebord(i: MatchInputs): WhyPayload | null {
  if (!i.weekPrev) return null;
  const v = 100 - i.weekPrev.horaires;
  if (v <= 40) return null;
  return {
    label: `${v}% de débordements horaires`,
    value: v,
    max: 100,
    threshold: 40,
    kind: "debord",
  };
}

function triggerVolume(i: MatchInputs): WhyPayload | null {
  if (i.weekPrevMeetingsHours == null) return null;
  const v = Math.round(i.weekPrevMeetingsHours);
  if (v <= 20) return null;
  return {
    label: `${v}h de réunions cette semaine`,
    value: v,
    max: 40,
    threshold: 20,
    kind: "volume",
  };
}

function triggerAnticipation(i: MatchInputs): WhyPayload | null {
  if (i.weekNextMeetingsHours == null || !i.weeks4MeetingsHoursAvg) return null;
  const ratio = i.weekNextMeetingsHours / i.weeks4MeetingsHoursAvg;
  if (ratio <= 1.2) return null;
  const pct = Math.round(ratio * 100);
  return {
    label: `Semaine à venir : ${pct}% du volume habituel`,
    value: pct,
    max: 200,
    threshold: 120,
    kind: "anticipation",
  };
}

function triggerChronique(i: MatchInputs): WhyPayload | null {
  if (!i.debordChronique3w) return null;
  // Pour l'affichage, on prend la valeur S-1 si dispo
  const v = i.weekPrev ? 100 - i.weekPrev.horaires : 60;
  return {
    label: `Débordements > 50% sur 3 semaines`,
    value: v,
    max: 100,
    threshold: 50,
    kind: "chronique",
  };
}

// ============================================================
// Pipeline principal
// ============================================================

interface Candidate {
  reco: Reco;
  why: WhyPayload;
  /** Écart au seuil, normalisé 0-1 (1 = très au-dessus du seuil). */
  gap: number;
}

/**
 * Calcule un `gap` normalisé en [0, 1] : 0 = juste au seuil, 1 = à 100%
 * de la distance entre le seuil et la borne extrême du graphe (`max`).
 *
 * Pour les triggers `inverse` (ex: plages de concentration), la distance
 * est inversée : la valeur est sous le seuil, on regarde l'écart vers 0.
 */
function computeGap(why: WhyPayload): number {
  if (why.inverse) {
    // valeur sous le seuil → distance vers 0
    return Math.max(0, Math.min(1, (why.threshold - why.value) / why.threshold));
  }
  // valeur au-dessus du seuil → distance vers `max`
  const range = why.max - why.threshold;
  if (range <= 0) return 0;
  return Math.max(0, Math.min(1, (why.value - why.threshold) / range));
}

/**
 * Sélectionne les 3 priorités à afficher, en suivant les principes 1, 2, 4
 * de la spec (le 3 "anti-répétition par historique" est out-of-scope v0).
 */
export function pickPriorities(inputs: MatchInputs, max = 3): Priority[] {
  // Étape 1 : candidates
  const candidates: Candidate[] = [];
  for (const reco of RECOS) {
    const rule = RULES[reco.id];
    if (!rule) continue; // pas de règle implémentée → reste en bibliothèque
    const why = rule(inputs);
    if (!why) continue;
    // Étape 2 : exclure essayée / pasPourMoi
    const status = inputs.statuses.get(reco.id);
    if (status === "essayee" || status === "pasPourMoi") continue;
    candidates.push({ reco, why, gap: computeGap(why) });
  }

  // Étape 3 : tri principe 1 (gap desc) puis principe 2 (impact desc puis
  // effort asc — ce qui matche les cas concrets §6 du doc).
  candidates.sort((a, b) => {
    const dGap = b.gap - a.gap;
    if (Math.abs(dGap) > 0.01) return dGap;
    const dImp = b.reco.impact - a.reco.impact;
    if (dImp !== 0) return dImp;
    return a.reco.effort - b.reco.effort;
  });

  // Étape 4 : diversité éditoriale (max 1 reco par thème dans le top `max`).
  // Si pas assez de thèmes distincts, on renvoie moins de `max` priorités —
  // mieux vaut 2 priorités que matraquer le même thème.
  const picked: Candidate[] = [];
  const usedThemes = new Set<ThemeKey>();
  for (const c of candidates) {
    if (picked.length >= max) break;
    if (usedThemes.has(c.reco.theme)) continue;
    picked.push(c);
    usedThemes.add(c.reco.theme);
  }

  return picked.map((c) => ({ reco: c.reco, why: c.why }));
}

// Exposer pour tests unitaires
export const _internal = { computeGap, RULES };
