import * as React from "react";
import styles from "./DetailScoringCard.module.css";
import type { Reco } from "../../data/recos";
import type { RecoStatus } from "../../data/statusStore";

export interface DetailScoringCardProps {
  reco: Reco;
  status: RecoStatus;
  onMark: (id: number, status: RecoStatus) => void;
}

/**
 * Sidebar de la page détail : effort + impact + boutons d'action.
 * En v0, "Recos liées" est volontairement omis.
 */
export const DetailScoringCard: React.FC<DetailScoringCardProps> = ({
  reco,
  status,
  onMark,
}) => {
  const isEssayee = status === "essayee";
  const isPasPourMoi = status === "pasPourMoi";

  return (
    <aside className={styles.card}>
      <div className={styles.eyebrow}>Scoring</div>

      <div className={styles.row}>
        <div className={styles.rowHead}>
          <span className={styles.rowLabel}>Effort</span>
          <span className={styles.rowValue}>{reco.effort}/5</span>
        </div>
        <span className={styles.pips} aria-hidden>
          {[1, 2, 3, 4, 5].map((i) => (
            <span
              key={i}
              className={`${styles.pip} ${i <= reco.effort ? styles.pipOn : ""}`}
            />
          ))}
        </span>
      </div>

      <div className={styles.divider} />

      <div className={styles.impactRow}>
        <span className={styles.rowLabel}>Impact IRA estimé</span>
        <span className={styles.impactValue}>+{reco.impact} pts</span>
      </div>

      <div className={styles.divider} />

      <div className={styles.actions}>
        {isEssayee ? (
          <div className={styles.essayeeBadge}>
            <span className="material-symbols-rounded" aria-hidden>
              check_circle
            </span>
            Reco marquée comme essayée
          </div>
        ) : (
          <button
            type="button"
            className={`${styles.btn} ${styles.btnPrimary}`}
            onClick={() => onMark(reco.id, "essayee")}
          >
            <span className="material-symbols-rounded" aria-hidden>
              check
            </span>
            Marquer comme essayée
          </button>
        )}
        <button
          type="button"
          className={`${styles.btn} ${styles.btnGhost}`}
          onClick={() =>
            onMark(reco.id, isPasPourMoi ? "new" : "pasPourMoi")
          }
        >
          {isPasPourMoi
            ? "Réafficher dans les priorités"
            : "Pas pour moi cette semaine"}
        </button>
      </div>
    </aside>
  );
};
