import * as React from "react";
import { useEffect, useState } from "react";
import { Routes, Route, useLocation, useNavigate } from "react-router-dom";
import styles from "./AppShell.module.css";
import { Topbar } from "../Topbar/Topbar";
import { Tabs, TabKey } from "../Tabs/Tabs";
import { useDashboardData } from "../../data/data-provider";
import { PolicyPanel } from "../PolicyPanel/PolicyPanel";
import { RythmeTab } from "../../RythmeTab";
import { AccompagnementTab } from "../../../accompagnement/AccompagnementTab";
import {
  DashboardStateView,
} from "../../../DashboardApp";
import { useGraphDashboard } from "../../data/useGraphDashboard";

export interface AppShellProps {
  /** Résultat du hook useGraphDashboard, propagé pour les états loading/auth/error. */
  dash: ReturnType<typeof useGraphDashboard>;
}

const MIN_WIDTH = 1100;

/**
 * Mappe le pathname courant → tab active. Utilisé pour synchroniser le
 * highlight des tabs avec la route. Toute URL `/accompagnement/...` est
 * considérée comme active sur l'onglet "accompagnement".
 */
function tabFromPath(pathname: string): TabKey {
  if (pathname.startsWith("/accompagnement")) return "accompagnement";
  if (pathname.startsWith("/qvct")) return "qvct";
  return "rythme";
}

/** URL d'entrée pour chaque onglet. */
const TAB_HOME: Record<TabKey, string> = {
  rythme: "/",
  accompagnement: "/accompagnement",
  qvct: "/qvct",
};

/**
 * AppShell : Topbar + Tabs + conteneur d'onglets.
 *
 * v1.6 : navigation entre onglets pilotée par react-router (HashRouter au
 * niveau racine). Les sous-routes de l'onglet Accompagnement vivent dans
 * `<AccompagnementTab>` via un `<Routes>` imbriqué.
 */
export const AppShell: React.FC<AppShellProps> = ({ dash }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const active = tabFromPath(location.pathname);

  const [narrow, setNarrow] = useState<boolean>(
    typeof window !== "undefined" ? window.innerWidth < MIN_WIDTH : false
  );
  const { referenceDate } = useDashboardData();

  useEffect(() => {
    const onResize = () => setNarrow(window.innerWidth < MIN_WIDTH);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  if (narrow) {
    return (
      <div className={styles.narrowGuard}>
        <div>
          <strong>Veuillez élargir le volet</strong>
          Le dashboard Gr33t nécessite au moins 1100 px de large.
        </div>
      </div>
    );
  }

  // États non-ready : on rend Topbar + Tabs + StateView (auth/loading/error)
  // dans le pane rythme. Les autres onglets restent navigables.
  const stateView = dash.status !== "ready" ? <DashboardStateView dash={dash} /> : null;

  return (
    <div className={styles.shell}>
      <Topbar referenceDate={referenceDate} />
      <Tabs active={active} onChange={(k) => navigate(TAB_HOME[k])} />
      <main className={styles.content}>
        <Routes>
          <Route
            path="/"
            element={
              <div className={`${styles.pane} ${styles.active}`}>
                {stateView ?? <RythmeTab />}
              </div>
            }
          />
          <Route
            path="/accompagnement/*"
            element={
              <div className={`${styles.pane} ${styles.active}`}>
                <AccompagnementTab />
              </div>
            }
          />
          <Route
            path="/qvct"
            element={
              <div className={`${styles.pane} ${styles.active}`}>
                <PolicyPanel />
              </div>
            }
          />
        </Routes>
      </main>
    </div>
  );
};
