/**
 * Détection des plages de focus sur une journée donnée.
 *
 * Un "focus block" = intervalle ≥ 30 min dans la plage de travail sans réunion
 * ni envoi de mail. Les blocs ≥ 2h sont classés "deep" (ils comptent pour le
 * facteur Concentration IRA v1.1). Les blocs 30min–<2h sont classés "plage"
 * (visibles dans le calendrier mais hors formule IRA).
 */
import type { DailyMeeting, DailySend } from "../dashboard/rythme/scoring/daily";
import type { QvctPolicy } from "../dashboard/rythme/config/policy";

export interface FocusBlock {
  start: Date;
  end: Date;
  durationMs: number;
  /**
   * "deep" = ≥ 2h (compte pour le facteur Concentration dans l'IRA)
   * "plage" = 30 min – < 2h (visibilité calendrier uniquement)
   */
  kind: "deep" | "plage";
}

const DEEP_MIN_MS = 2 * 60 * 60 * 1000;
const PLAGE_MIN_MS = 30 * 60 * 1000;

/**
 * Calcule les blocs de focus du jour. Retourne les blocs ≥ 30 min, classés
 * "deep" (≥2h) ou "plage" (30min–<2h), dans l'ordre chronologique.
 *
 * Aligné sur la logique du facteur Concentration v1.1 :
 *   - Fenêtre = [max(first, workStart), min(last, workEnd)]
 *   - Intervalles hors réunion dans cette fenêtre
 *   - Coupure à chaque envoi de mail
 */
export function computeFocusBlocks(
  isoDate: string,
  meetings: DailyMeeting[],
  sends: DailySend[],
  policy: QvctPolicy
): FocusBlock[] {
  const [y, mo, dd] = isoDate.split("-").map(Number);
  const wStart = new Date(y, mo - 1, dd, policy.workStart.h, policy.workStart.m, 0, 0);
  const wEnd = new Date(y, mo - 1, dd, policy.workEnd.h, policy.workEnd.m, 0, 0);

  const allTimes: Date[] = [
    ...meetings.flatMap((m) => [m.start, m.end]),
    ...sends.map((s) => s.sentAt),
  ];
  if (allTimes.length === 0) return [];

  const first = new Date(Math.min(...allTimes.map((d) => d.getTime())));
  const last = new Date(Math.max(...allTimes.map((d) => d.getTime())));
  const start = first > wStart ? first : wStart;
  const end = last < wEnd ? last : wEnd;
  if (end.getTime() <= start.getTime()) return [];

  // Intervalles hors réunion dans la fenêtre
  const sorted = [...meetings]
    .filter((m) => m.end > start && m.start < end)
    .sort((a, b) => a.start.getTime() - b.start.getTime());
  const nonMeeting: [number, number][] = [];
  let cursor = start.getTime();
  for (const m of sorted) {
    const mStart = Math.max(m.start.getTime(), start.getTime());
    const mEnd = Math.min(m.end.getTime(), end.getTime());
    if (cursor < mStart) nonMeeting.push([cursor, mStart]);
    cursor = Math.max(cursor, mEnd);
  }
  if (cursor < end.getTime()) nonMeeting.push([cursor, end.getTime()]);

  // Découpe par envois mail, garder les segments ≥ PLAGE_MIN_MS
  const blocks: FocusBlock[] = [];
  for (const [a, b] of nonMeeting) {
    const cuts = sends
      .map((s) => s.sentAt.getTime())
      .filter((t) => t > a && t < b)
      .sort((x, y) => x - y);
    const points = [a, ...cuts, b];
    for (let i = 0; i < points.length - 1; i++) {
      const segStart = points[i];
      const segEnd = points[i + 1];
      const seg = segEnd - segStart;
      if (seg >= PLAGE_MIN_MS) {
        blocks.push({
          start: new Date(segStart),
          end: new Date(segEnd),
          durationMs: seg,
          kind: seg >= DEEP_MIN_MS ? "deep" : "plage",
        });
      }
    }
  }
  return blocks.sort((a, b) => a.start.getTime() - b.start.getTime());
}

/** Formatage lisible d'une durée : "45min" / "1h" / "2h06" / "2h23". */
export function formatDuration(ms: number): string {
  const min = Math.round(ms / 60000);
  if (min < 60) return `${min}min`;
  const h = Math.floor(min / 60);
  const m = min % 60;
  return m > 0 ? `${h}h${m.toString().padStart(2, "0")}` : `${h}h`;
}
