import * as React from "react";
import { useNavigate } from "react-router-dom";
import styles from "./RecoCard.module.css";
import { IndicatorBar } from "../IndicatorBar/IndicatorBar";
import { THEMES } from "../../data/themes";
import type { Reco } from "../../data/recos";
import type { RecoStatus } from "../../data/statusStore";
import type { WhyPayload } from "../../scoring/match";
import { formatWhy } from "../../scoring/whyDisplay";

export interface RecoCardProps {
  reco: Reco;
  /** Présent si la carte est contextualisée (priorité) → ruban + mini-graph. */
  why?: WhyPayload;
  /** Statut utilisateur (pilote l'apparence + les actions). */
  status: RecoStatus;
  /** Mode compact = pas de mini-graph (utilisé en vue thématique). */
  compact?: boolean;
  /** Marquer la reco essayée. */
  onMark: (id: number, status: RecoStatus) => void;
}

const STATUS_LABEL: Record<RecoStatus, string> = {
  new: "Nouvelle",
  essayee: "Essayée",
  pasPourMoi: "Pas pour moi",
};

/**
 * Carte de recommandation. Cliquable globalement pour ouvrir la page détail.
 * Le footer contient : pips d'effort, chip d'impact IRA et boutons d'action.
 */
export const RecoCard: React.FC<RecoCardProps> = ({
  reco,
  why,
  status,
  compact = false,
  onMark,
}) => {
  const navigate = useNavigate();
  const theme = THEMES[reco.theme];
  const showMiniGraph = !!why && !compact;

  const onView = () => navigate(`/accompagnement/reco/${reco.id}`);
  const onClickMark = (e: React.MouseEvent) => {
    e.stopPropagation();
    onMark(reco.id, status === "essayee" ? "new" : "essayee");
  };

  return (
    <article
      className={`${styles.card} ${status === "essayee" ? styles.essayee : ""}`}
      onClick={onView}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === "Enter") onView();
      }}
      aria-label={`Recommandation : ${reco.title}`}
    >
      {why && (
        <div
          className={styles.why}
          style={{ background: theme.softVar, color: theme.onVar }}
        >
          <span className="material-symbols-rounded" aria-hidden>
            insights
          </span>
          <span>
            <b>Pourquoi cette reco · </b>
            {why.label}
          </span>
        </div>
      )}

      <div className={styles.body}>
        <div className={styles.topline}>
          <span
            className={styles.tag}
            style={{ background: theme.softVar, color: theme.onVar }}
          >
            <span
              className={styles.dot}
              style={{ background: theme.colorVar }}
            />
            {theme.short}
          </span>
          <span
            className={`${styles.status} ${styles[`status_${status}`]}`}
            aria-label={`Statut : ${STATUS_LABEL[status]}`}
          >
            {status === "essayee" && (
              <span className="material-symbols-rounded" aria-hidden>
                check_circle
              </span>
            )}
            {STATUS_LABEL[status]}
          </span>
        </div>

        <h3 className={styles.title}>{reco.title}</h3>
        <p className={styles.lim}>{reco.limite}</p>

        {showMiniGraph && why && (
          <div className={styles.miniGraph}>
            {(() => {
              const fmt = formatWhy(why);
              return (
                <IndicatorBar
                  value={why.value}
                  max={why.max}
                  threshold={why.threshold}
                  inverse={why.inverse}
                  unit={fmt.unit}
                  label={fmt.contextLabel}
                  valueDisplay={fmt.valueDisplay}
                  thresholdDisplay={fmt.thresholdDisplay}
                />
              );
            })()}
          </div>
        )}
      </div>

      <div className={styles.footer}>
        <span className={styles.effort}>
          <span className={styles.effortLabel}>EFFORT</span>
          <span className={styles.pips}>
            {[1, 2, 3, 4, 5].map((i) => (
              <span
                key={i}
                className={`${styles.pip} ${i <= reco.effort ? styles.pipOn : ""}`}
              />
            ))}
          </span>
        </span>
        <span className={styles.impact}>
          <span className="material-symbols-rounded" aria-hidden>
            trending_up
          </span>
          IRA +{reco.impact} pts
        </span>
        <div className={styles.actions}>
          {status !== "essayee" && (
            <button
              type="button"
              className={`${styles.btn} ${styles.btnGhost}`}
              onClick={onClickMark}
              aria-label="Marquer comme essayée"
            >
              <span className="material-symbols-rounded" aria-hidden>
                check
              </span>
              Essayée
            </button>
          )}
          <button
            type="button"
            className={`${styles.btn} ${styles.btnPrimary}`}
            onClick={(e) => {
              e.stopPropagation();
              onView();
            }}
          >
            Voir l'action
            <span className="material-symbols-rounded" aria-hidden>
              arrow_forward
            </span>
          </button>
        </div>
      </div>
    </article>
  );
};
