import * as React from "react";
import styles from "./FactorDetailDrawer.module.css";
import type { Levier, FactorBreakdown, FactorEvent } from "../../types/data-contract";

interface Props {
  levier: Levier;
  breakdown: FactorBreakdown;
  onClose: () => void;
}

/**
 * Tiroir latéral droit qui détaille les événements derrière un facteur.
 *
 * Affiche 2 sections : "Ce qui a réduit le score" (négatifs) puis
 * "Ce qui a contribué" (positifs). Chaque ligne porte la date, l'heure
 * et un détail explicatif.
 */
export const FactorDetailDrawer: React.FC<Props> = ({
  levier,
  breakdown,
  onClose,
}) => {
  // Fermeture par Escape
  React.useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  return (
    <>
      <div className={styles.backdrop} onClick={onClose} />
      <aside
        className={styles.drawer}
        role="dialog"
        aria-modal="true"
        aria-label={`Détail ${levier.positive.label}`}
      >
        <header className={styles.header}>
          <div className={styles.headerLeft}>
            <div className={styles.title}>{levier.positive.label}</div>
            <div className={styles.subtitle}>
              Sur les 30 derniers jours travaillés
            </div>
          </div>
          <button
            type="button"
            className={styles.closeBtn}
            onClick={onClose}
            aria-label="Fermer"
          >
            ×
          </button>
        </header>

        <div className={styles.scoreRow}>
          <div className={styles.scoreSide}>
            <div
              className={styles.scoreVal}
              style={{ color: levier.positive.colorVar }}
            >
              {levier.positive.percent}%
            </div>
            <div className={styles.scoreLabel}>{levier.positive.label}</div>
          </div>
          <div className={styles.scoreSide}>
            <div
              className={styles.scoreVal}
              style={{ color: levier.negative.colorVar }}
            >
              {levier.negative.percent}%
            </div>
            <div className={styles.scoreLabel}>{levier.negative.label}</div>
          </div>
        </div>

        <div className={styles.body}>
          <Section
            title={levier.negative.label}
            count={breakdown.negatives.length}
            events={breakdown.negatives}
            color={levier.negative.colorVar}
            empty="Aucun événement défavorable détecté sur les 30 derniers jours."
            defaultOpen={true}
          />
          <Section
            title={levier.positive.label}
            count={breakdown.positives.length}
            events={breakdown.positives}
            color={levier.positive.colorVar}
            empty="Aucun événement favorable détecté sur les 30 derniers jours."
            defaultOpen={true}
          />
        </div>
      </aside>
    </>
  );
};

interface SectionProps {
  title: string;
  count: number;
  events: FactorEvent[];
  color: string;
  empty: string;
  defaultOpen: boolean;
}

const Section: React.FC<SectionProps> = ({
  title,
  count,
  events,
  color,
  empty,
  defaultOpen,
}) => {
  const [open, setOpen] = React.useState(defaultOpen);
  return (
    <section className={`${styles.section} ${open ? styles.sectionOpen : styles.sectionClosed}`}>
      <button
        type="button"
        className={styles.sectionHeader}
        onClick={() => setOpen((v) => !v)}
        aria-expanded={open}
      >
        <span className={styles.sectionDot} style={{ background: color }} />
        <span className={styles.sectionTitle}>{title}</span>
        <span className={styles.sectionCount}>{count}</span>
        <span className={styles.sectionToggle} aria-hidden>
          {open ? "−" : "+"}
        </span>
      </button>
      {open && (
        <div className={styles.list}>
          {events.length === 0 ? (
            <div className={styles.empty}>{empty}</div>
          ) : (
            events.map((ev, i) => (
              <EventRow key={`${ev.date}-${ev.time}-${i}`} event={ev} />
            ))
          )}
        </div>
      )}
    </section>
  );
};

const EventRow: React.FC<{ event: FactorEvent }> = ({ event }) => {
  return (
    <div className={styles.row}>
      <div className={styles.rowDate}>{formatDateShort(event.date)}</div>
      <div className={styles.rowMain}>
        <div className={styles.rowTitle}>{event.title}</div>
        <div className={styles.rowDetail}>
          {event.time && (
            <span className={styles.timePill}>
              {event.time}
              {event.endTime ? `–${event.endTime}` : ""}
            </span>
          )}
          <span>{event.detail}</span>
        </div>
      </div>
    </div>
  );
};

const SHORT_DAYS = ["Dim", "Lun", "Mar", "Mer", "Jeu", "Ven", "Sam"];
const SHORT_MONTHS = [
  "janv.",
  "févr.",
  "mars",
  "avr.",
  "mai",
  "juin",
  "juil.",
  "août",
  "sept.",
  "oct.",
  "nov.",
  "déc.",
];

function formatDateShort(iso: string): string {
  const [y, m, d] = iso.split("-").map(Number);
  const dt = new Date(y, m - 1, d);
  return `${SHORT_DAYS[dt.getDay()]} ${d} ${SHORT_MONTHS[m - 1]}`;
}
